// scanTaskEntry scans a single row into a TaskEntry.
func scanTaskEntry(row *sql.Row) (TaskEntry, error) {
	var filename, status, description, branch, topic, createdAt, implemented, content, clickupTaskID string
	var reviewCycle int
	if err := row.Scan(&filename, &status, &description, &branch, &topic, &createdAt, &implemented, &content, &clickupTaskID, &reviewCycle); err != nil {
		if err == sql.ErrNoRows {
			return TaskEntry{}, fmt.Errorf("plan not found")
		}
		return TaskEntry{}, fmt.Errorf("scan plan: %w", err)
	}
	return TaskEntry{
		Filename:      filename,
		Status:        Status(status),
		Description:   description,
		Branch:        branch,
		Topic:         topic,
		CreatedAt:     parseTime(createdAt),
		Implemented:   implemented,
		Content:       content,
		ClickUpTaskID: clickupTaskID,
		ReviewCycle:   reviewCycle,
	}, nil
}

// scanTaskEntries scans multiple rows into a slice of TaskEntry.
func scanTaskEntries(rows *sql.Rows) ([]TaskEntry, error) {
	var entries []TaskEntry
	for rows.Next() {
		var filename, status, description, branch, topic, createdAt, implemented, content, clickupTaskID string
		var reviewCycle int
		if err := rows.Scan(&filename, &status, &description, &branch, &topic, &createdAt, &implemented, &content, &clickupTaskID, &reviewCycle); err != nil {
			return nil, fmt.Errorf("scan plan: %w", err)
		}
		entries = append(entries, TaskEntry{
			Filename:      filename,
			Status:        Status(status),
			Description:   description,
			Branch:        branch,
			Topic:         topic,
			CreatedAt:     parseTime(createdAt),
			Implemented:   implemented,
			Content:       content,
			ClickUpTaskID: clickupTaskID,
			ReviewCycle:   reviewCycle,
		})
	}
	if err := rows.Err(); err != nil {
		return nil, fmt.Errorf("iterate tasks: %w", err)
	}
	return entries, nil
}

// formatTime formats a time.Time as RFC3339 for storage. Zero time returns empty string.
func formatTime(t time.Time) string {
	if t.IsZero() {
		return ""
	}
	return t.UTC().Format(time.RFC3339Nano)
}

// parseTime parses an RFC3339 string. Returns zero time on empty or invalid input.
func parseTime(s string) time.Time {
	if s == "" {
		return time.Time{}
	}
	t, err := time.Parse(time.RFC3339Nano, s)
	if err != nil {
		return time.Time{}
	}
	return t
}

// isUniqueConstraintError returns true if the error is a SQLite UNIQUE constraint violation.
func isUniqueConstraintError(err error) bool {
	if err == nil {
		return false
	}
	return strings.Contains(err.Error(), "UNIQUE constraint failed")
}

